<script lang="ts">
 import{onMount}from'svelte';import StaxAudio from'$lib/components/StaxAudio.svelte';import StaxScene from'$lib/components/stax/StaxScene.svelte';import ControllerStatus from'./ControllerStatus.svelte';import MatchResult from'./MatchResult.svelte';import MatchStandings from'./MatchStandings.svelte';import LevelPicker from'./LevelPicker.svelte';import OpponentList from'./OpponentList.svelte';import{auth,firebaseConfigured}from'$lib/firebase/config';import{joinRoom,subscribeRoom,subscribeRoomPlayers,updatePlayerLevel,type RoomPlayer}from'$lib/firebase/rooms';import{createStaxController,requestStaxRematch,type StaxControllerState,type StaxProgress}from'$lib/firebase/stax';import type{StaxInput}from'$lib/game/stax';import{OneShotGamepadButton,StandardGamepadControls,type GamepadControlAction}from'$lib/input/gamepad';
 let code='',name='',error='',gameId='',roomId='',online=true,gamepadName='',selectedLevel=0,chainCueSignal=0,players:RoomPlayer[]=[];let controller:ReturnType<typeof createStaxController>|undefined,state:StaxControllerState={tick:0,ready:false},stopRoom=()=>{},stopPlayers=()=>{},frame=0,shoulders=false;const pad=new StandardGamepadControls(),restartButton=new OneShotGamepadButton(),accelerateSources=new Set<string>();$:enabled=Boolean(state.ready&&state.state?.phase==='playing'&&!state.lifecycle?.finished);$:standings=(state.lifecycle?.playerIds??[]).map((id,i)=>({playerId:id,name:players.find(p=>p.uid===id)?.displayName??`Player ${i+1}`,score:state.lifecycle?.scores[id]??0})).sort((a,b)=>b.score-a.score);
 onMount(()=>{void init();frame=requestAnimationFrame(poll);const kd=(e:KeyboardEvent)=>{if(e.repeat&&['ArrowUp','ArrowDown',' ','Shift','r','R'].includes(e.key))return;if(e.key==='ArrowLeft'||e.key==='ArrowRight'){e.preventDefault();send({type:'input/move',payload:{dx:e.key==='ArrowLeft'?-1:1}})}else if(e.key==='ArrowDown'){e.preventDefault();accelerate('keyboard-down',true)}else if(e.key===' '){e.preventDefault();send({type:'input/place',payload:{}})}else if(e.key==='ArrowUp'){e.preventDefault();send({type:'input/throw-back',payload:{}})}else if(e.key==='Shift'){accelerate('keyboard-shift',true)}else if(e.key.toLowerCase()==='r'){send({type:'input/restart',payload:{}})}};const ku=(e:KeyboardEvent)=>{if(e.key==='ArrowDown')accelerate('keyboard-down',false);else if(e.key==='Shift')accelerate('keyboard-shift',false)};window.addEventListener('keydown',kd);window.addEventListener('keyup',ku);return()=>{cancelAnimationFrame(frame);controller?.destroy();stopRoom();stopPlayers();window.removeEventListener('keydown',kd);window.removeEventListener('keyup',ku)}});
 async function init(){code=new URL(location.href).searchParams.get('code')?.toUpperCase()??'';name=localStorage.getItem('drm-player-name')??'';if(!firebaseConfigured){error='Firebase configuration is required.';return}try{const room=await joinRoom(code,name);roomId=room.id;stopPlayers=subscribeRoomPlayers(room.id,p=>{players=p;selectedLevel=p.find(x=>x.uid===auth?.currentUser?.uid)?.level??selectedLevel},e=>error=e.message);if(room.activeGameId)start(room.activeGameId);stopRoom=subscribeRoom(room.id,next=>{if(next.activeGameId)start(next.activeGameId)},e=>error=e.message)}catch(e){error=e instanceof Error?e.message:String(e)}}
 function start(id:string){if(id===gameId)return;gameId=id;controller?.destroy();controller=createStaxController(id,next=>{state=next;if(next.error)error=next.error})}function send(input:StaxInput){if(enabled)controller?.command(input)}function accelerate(source:string,active:boolean){const wasActive=accelerateSources.size>0;if(active)accelerateSources.add(source);else accelerateSources.delete(source);const isActive=accelerateSources.size>0;if(isActive!==wasActive)send({type:isActive?'input/accelerate-start':'input/accelerate-end',payload:{}})}function lane(target:number){if(!state.state)return;for(let at=state.state.paddleLane;at!==target;at+=target>at?1:-1)send({type:'input/move',payload:{dx:target>at?1:-1}});if(state.state.paddle.length)send({type:'input/place',payload:{}})}
 function action(a:GamepadControlAction){if(a==='move-left'||a==='move-right')send({type:'input/move',payload:{dx:a==='move-left'?-1:1}});else if(a==='hard-drop'||a==='rotate-counterclockwise')send({type:'input/throw-back',payload:{}});else if(a==='rotate-clockwise')send({type:'input/place',payload:{}});else if(a==='soft-drop-start'||a==='soft-drop-end')accelerate('gamepad-down',a==='soft-drop-start')}function poll(now:number){const pads=typeof navigator.getGamepads==='function'?Array.from(navigator.getGamepads()):[],active=pads.find(p=>p?.connected);gamepadName=active?.id??'';for(const a of pad.sample(pads,now))action(a);const held=pads.some(p=>Boolean(p?.buttons[4]?.pressed||p?.buttons[5]?.pressed));if(held!==shoulders){shoulders=held;accelerate('gamepad-shoulders',held)}if(restartButton.sample(pads))send({type:'input/restart',payload:{}});frame=requestAnimationFrame(poll)}async function chooseLevel(level:number){selectedLevel=level;if(roomId)await updatePlayerLevel(roomId,level)}async function next(){if(gameId)await requestStaxRematch(gameId,selectedLevel)}
</script>
{#if error}<main class="message"><h1 role="alert">{error}</h1>{#if state.ownershipConflict}<button on:click={()=>controller?.takeOver()}>Take over on this device</button>{/if}</main>{:else if !state.state}<main class="message"><h1>WAITING FOR STAX…</h1><LevelPicker level={selectedLevel} change={chooseLevel}/></main>{:else}<main class="controller"><StaxAudio enabled={state.audioOutput==='controllers'} phase={state.state.phase} survived={state.state.survived} placements={state.state.placements} chains={chainCueSignal} misses={state.state.misses} returns={state.state.throws}/><ControllerStatus {online} ready={state.ready} {gamepadName} room={code}/><section><div class="hud"><b>{name}</b><span>LEVEL {state.state.level}</span><span>SCORE {state.state.score}</span><span>{state.state.objective.kind.toUpperCase()} {state.state.objective.progress}/{state.state.objective.target}</span><span>MISSES {state.state.misses}/{state.state.missLimit}</span></div><StaxScene state={state.state} selectLane={lane} onChainCue={()=>chainCueSignal++} onTerminalPresentationComplete={()=>controller?.finishPresentation()}/><div class="controls"><button on:pointerdown={()=>send({type:'input/restart',payload:{}})}>RESET</button><button on:pointerdown={()=>send({type:'input/throw-back',payload:{}})}>THROW BACK</button><button on:pointerdown={()=>send({type:'input/place',payload:{}})}>PLACE</button><button on:pointerdown={()=>send({type:'input/accelerate-start',payload:{}})} on:pointerup={()=>send({type:'input/accelerate-end',payload:{}})}>HURRY</button></div></section><OpponentList opponents={state.opponents??[]} let:opponent><StaxScene state={(opponent as StaxProgress).state} compact/></OpponentList>{#if state.lifecycle?.finished}<MatchResult title={state.lifecycle.matchComplete?'MATCH COMPLETE':'ROUND COMPLETE'} action={state.lifecycle.matchComplete?'PLAY AGAIN':'NEXT ROUND'} ready={state.lifecycle.readyPlayerIds.length} total={state.lifecycle.playerIds.length} disabled={state.lifecycle.readyPlayerIds.includes(state.playerId??'')} level={selectedLevel} changeLevel={l=>selectedLevel=l} activate={next}>{#if state.lifecycle.matchComplete}<MatchStandings entries={standings}/>{/if}</MatchResult>{/if}</main>{/if}
<style>.controller{min-height:100dvh;padding:.5rem;display:grid;place-items:center}.controller section{display:grid;place-items:center;max-height:100dvh}.hud{display:flex;gap:.8rem;flex-wrap:wrap;justify-content:center;font-size:.7rem}.controls{display:grid;grid-template-columns:repeat(4,1fr);gap:.5rem;width:100%;max-width:620px}.controls button{padding:.7rem}.message{min-height:100vh;display:grid;place-content:center}@media(orientation:portrait){.controller :global(.opponents){display:none}}</style>
